    printFont.m_nDirectory = 1;
    printFont.m_aFontFile = OString("Caladea-Bold.ttf");
    printFont.m_nCollectionEntry = 0;
    printFont.m_nVariationEntry = 0;
    SetCaladeaBoldFont(printFont.m_aFontAttributes);
